function solve(sx: number, sy: number, tx: number, ty: number): number {
    let count = 0;
    while (tx > sx || ty > sy) {
        if (tx === sx && ty === sy) {
            return count;
        }
        if (tx > ty) {
            if (ty < sy) {
                return -1;
            }
            const steps = Math.max(1, Math.floor((tx - sx) / ty));
            tx -= steps * ty;
            count += steps;
        } else {
            if (tx < sx) {
                return -1;
            }
            const steps = Math.max(1, Math.floor((ty - sy) / tx));
            ty -= steps * tx;
            count += steps;
        }
    }
    return tx === sx && ty === sy ? count : -1;
}
